import { headers } from 'next/headers'
import Link from 'next/link'

import { BlogNavButton } from '@/components/BlogNavButton'
import { getRecentPosts } from '@/lib/posts'

export const metadata = {
  title: 'Home',
  description: 'Welcome to my blog homepage',
  openGraph: {
    title: 'Home - My Blog',
  },
}

export default async function HomePage() {
  const [posts, headerStore] = await Promise.all([getRecentPosts(), headers()])
  const userAgent = headerStore.get('user-agent') ?? ''
  const timestamp = new Date().toISOString()

  return (
    <div>
      <h1>Welcome to My Blog</h1>
      <p>Server-side rendered at: {timestamp}</p>
      <p>Your user agent: {userAgent}</p>

      <h2>Recent Posts</h2>
      <ul>
        {posts.map((post) => (
          <li key={post.id}>
            <Link href={`/blog/${post.id}`}>{post.title}</Link>
          </li>
        ))}
      </ul>

      <BlogNavButton />
    </div>
  )
}

import { PostCard } from '@/components/PostCard'
import { getAllPosts } from '@/lib/posts'

export const metadata = {
  title: 'Blog',
  description: 'All blog posts',
}

export default async function BlogIndexPage() {
  const posts = await getAllPosts()

  return (
    <div>
      <h1>All Blog Posts</h1>

      <div className="posts-grid">
        {posts.map((post) => (
          <PostCard key={post.id} post={post} />
        ))}
      </div>
    </div>
  )
}
